#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAX 1000

int abs(int x) { return x < 0 ? -x : x; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X, Y, K;
        scanf("%d %d %d", &X, &Y, &K);
        int AX, AY, BX, BY;
        scanf("%d %d %d %d", &AX, &AY, &BX, &BY);
        int blocked[K][2];
        for (int i = 0; i < K; i++) {
            scanf("%d %d", &blocked[i][0], &blocked[i][1]);
        }
        int queue[MAX * MAX][2];
        int front = 0, rear = 0;
        queue[rear][0] = 0;
        queue[rear][1] = 0;
        rear++;
        int ways = 0;
        int visited[MAX][MAX] = {0};
        while (front < rear) {
            int x = queue[front][0];
            int y = queue[front][1];
            front++;
            if (x == X && y == Y) {
                ways++;
                ways %= MOD;
            }
            if (x + AX >= -MAX && x + AX < MAX && y + AY >= -MAX && y + AY < MAX && !visited[x + AX][y + AY]) {
                int flag = 0;
                for (int i = 0; i < K; i++) {
                    if (x + AX == blocked[i][0] && y + AY == blocked[i][1]) {
                        flag = 1;
                        break;
                    }
                }
                if (!flag) {
                    queue[rear][0] = x + AX;
                    queue[rear][1] = y + AY;
                    rear++;
                    visited[x + AX][y + AY] = 1;
                }
            }
            if (x + BX >= -MAX && x + BX < MAX && y + BY >= -MAX && y + BY < MAX && !visited[x + BX][y + BY]) {
                int flag = 0;
                for (int i = 0; i < K; i++) {
                    if (x + BX == blocked[i][0] && y + BY == blocked[i][1]) {
                        flag = 1;
                        break;
                    }
                }
                if (!flag) {
                    queue[rear][0] = x + BX;
                    queue[rear][1] = y + BY;
                    rear++;
                    visited[x + BX][y + BY] = 1;
                }
            }
        }
        printf("%d\n", ways);
    }
    return 0;
}

