                        if (x + AX == blocked[i][0] && y + AY == blocked[i][1]) {
                            flag = true;
                            break;
                        }
                    }
                    if (!flag) {
                        q.add(new int[] {x + AX, y + AY});
                        visited[x + AX][y + AY] = true;
                    }
                }
