let idx = 0;
const MOD = 1000000007;
const MAX = 1000;

function nextLine() {
    return input[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}

for (let t = nextInt(); t > 0; t--) {
    let [X, Y, K] = nextInts();
    let [AX, AY, BX, BY] = nextInts();
    let blocked = [];
    for (let i = 0; i < K; i++) {
        blocked.push(nextInts());
    }
    let q = [[0, 0]];
    let ways = 0;
    let visited = Array(MAX).fill(0).map(() => Array(MAX).fill(false));
    while (q.length > 0) {
        let [x, y] = q.shift();
        if (x === X && y === Y) {
            ways++;
            ways %= MOD;
        }
        if (x + AX >= 0 && x + AX < MAX && y + AY >= 0 && y + AY < MAX && !visited[x + AX][y + AY]) {
            if (!blocked.some(b => b[0] === x + AX && b[1] === y + AY)) {
